mapper.select:
select q.id as quId,q.qu_type,q.repo_id,IF(er.id IS NULL, 0, 1) AS exercised,
er.is_right AS isRight from t_question as q left join
t_exercise_record as er on er.repo_id = q.repo_id and er.question_id = q.id and er.user_id = #{userId}

    q.repo_id = #{repoId}

        and q.qu_type = #{quType}


        and q.is_deleted = 0

select q.id, q.qu_type , q.content, q.course_id as courseId, c.name as courseName, q.chapter_id as chapterId, cc.title as chapterTitle, q.knowledge_point_id as knowledgePointId, kp.name as knowledgePointName, q.difficulty, r.title as repoTitle, q.create_time from t_question q join t_repo r on q.repo_id = r.id left join t_course c on q.course_id = c.id left join t_course_chapter cc on q.chapter_id = cc.id left join t_knowledge_point kp on q.knowledge_point_id = kp.id
q.is_deleted = 0
and q.content like concat('%',#{title},'%')
and q.repo_id = #{repoId}
and q.qu_type = #{type}
and q.course_id = #{courseId}
and q.chapter_id = #{chapterId}
and q.knowledge_point_id = #{knowledgePointId}
and q.difficulty = #{difficulty}
and q.user_id = #{userId}
